VALUES
  ('age_reversal', 1, 'Beginning the Journey', 'Phase 1 · Foundation', 'Complete Day 1 with steady, consistent action.', '{"day_number":1,"day_title":"Beginning the Journey","day_goal":"Complete Day 1 with steady, consistent action.","estimated_minutes":25,"phase_label":"Phase 1 · Foundation","phase_number":1,"intro_parameters":{"sets":2,"reps":3,"holdSeconds":8,"durationMinutes":25},"lesson_paragraphs":["Isometric holds activate the superficial muscular aponeurotic system (SMAS) — the same muscle layer that a facelift targets. Consistent daily activation signals fibroblasts to produce more collagen."],"lesson_highlight":null,"walk_step_label":"Step 1 · Body Circulation","walk_title":"20-Minute Walk","walk_subtitle":"Wakes up circulation before facial exercises","walk_instructions":["Walk at a comfortable pace for 20 minutes.","Keep your posture upright, shoulders relaxed.","Breathe naturally through the nose if possible."],"walk_purpose":"Improves blood circulation, supports cellular energy production, and reduces physical tension before facial work.","exercise_one_category":"Isometric Hold","exercise_one_name":"Cheek Lift Hold","exercise_one_target_muscle":"Zygomaticus muscles","exercise_one_steps":["Sit comfortably with your back straight.","Smile as wide as possible.","Place fingertips lightly on top of cheeks.","Lift cheek muscles upward toward the eyes.","Hold firmly."],"exercise_one_sets":2,"exercise_one_reps":3,"exercise_one_hold_seconds":8,"exercise_one_science_note":"Trains the SMAS layer — the same muscle layer facelift surgery targets — through consistent isometric activation.","exercise_two_category":"Isometric Hold","exercise_two_name":"Jawline Pucker Hold","exercise_two_target_muscle":"Masseter and neck muscles","exercise_two_steps":["Sit or stand with your back straight.","Tilt your head slightly upward toward the ceiling.","Pucker your lips as if kissing the ceiling.","Feel the stretch under the jaw and neck.","Hold firmly."],"exercise_two_sets":2,"